def _external_dna_pol_x_lyase_sequence_features(
    sequence: str,
    *,
    active_site_positions: list[int],
) -> dict[str, Any]:
    sequence = _clean_sequence(sequence)
    active_site_position_set = set(active_site_positions)
    active_site_lys_positions: list[int] = []
    active_site_lys_windows: list[dict[str, Any]] = []
    local_basic_total = 0
    local_acidic_total = 0
    for position in sorted(active_site_position_set):
        if position < 1 or position > len(sequence):
            continue
        residue = sequence[position - 1]
        window_start = max(1, position - 12)
        window_end = min(len(sequence), position + 12)
        window = sequence[window_start - 1 : window_end]
        basic_count = sum(1 for residue_code in window if residue_code in {"K", "R"})
        acidic_count = sum(1 for residue_code in window if residue_code in {"D", "E"})
        if residue == "K":
            active_site_lys_positions.append(position)
            local_basic_total += basic_count
            local_acidic_total += acidic_count
        active_site_lys_windows.append(
            {
                "position": position,
                "residue": residue,
                "window_start": window_start,
                "window_end": window_end,
                "window_sequence": window,
                "local_basic_residue_count": basic_count,
                "local_acidic_residue_count": acidic_count,
            }
        )

    has_source_active_site_lys = bool(active_site_lys_positions)
    has_basic_acidic_context = (
        has_source_active_site_lys
        and local_basic_total >= 4
        and local_acidic_total >= 2
    )
    if has_source_active_site_lys and has_basic_acidic_context:
        status = "dna_pol_x_lyase_axis_present_with_source_active_site_lys"
    elif has_source_active_site_lys:
        status = "partial_dna_pol_x_lyase_axis_signal"
    else:
        status = "dna_pol_x_lyase_axis_absent"

    return {
        "sequence_length": len(sequence),
        "source_active_site_positions": sorted(active_site_position_set),
        "source_active_site_lys_positions": active_site_lys_positions,
        "source_active_site_lys_count": len(active_site_lys_positions),
        "active_site_lys_local_windows": active_site_lys_windows,
        "active_site_lys_local_basic_residue_count": local_basic_total,
        "active_site_lys_local_acidic_residue_count": local_acidic_total,
        "has_source_active_site_lys": has_source_active_site_lys,
        "has_active_site_basic_acidic_context": has_basic_acidic_context,
        "dna_pol_x_lyase_sequence_axis_status": status,
    }


