def build_external_source_reaction_evidence_sample(
    *,
    evidence_request_export: dict[str, Any],
    max_candidates: int = 10,
    max_reactions_per_ec: int = 3,
    fetcher: Callable[[str, int], dict[str, Any]] = fetch_rhea_by_ec,
) -> dict[str, Any]:
    """Fetch bounded reaction context for external candidates without labels."""
    review_items = [
        item
        for item in evidence_request_export.get("review_items", [])
        if isinstance(item, dict)
    ][:max_candidates]
    rows: list[dict[str, Any]] = []
    candidate_summaries: list[dict[str, Any]] = []
    fetch_failures: list[dict[str, str]] = []
    queried_ec_numbers: set[str] = set()
    broad_ec_numbers: set[str] = set()
    for item in review_items:
        context = item.get("external_source_context", {})
        if not isinstance(context, dict):
            continue
        accession = _normalize_accession(context.get("accession"))
        ec_numbers = [
            str(ec).strip()
            for ec in context.get("ec_numbers", []) or []
            if str(ec).strip()
        ]
        candidate_record_count = 0
        candidate_broad_ec_numbers: list[str] = []
        for ec_number in ec_numbers:
            queried_ec_numbers.add(ec_number)
            ec_specificity = _ec_specificity(ec_number)
            if ec_specificity == "broad_or_incomplete":
                broad_ec_numbers.add(ec_number)
                candidate_broad_ec_numbers.append(ec_number)
            try:
                payload = fetcher(ec_number, max_reactions_per_ec)
            except Exception as exc:  # pragma: no cover - exercised by live artifacts
                fetch_failures.append(
                    {
                        "accession": accession,
                        "ec_number": ec_number,
                        "error_type": type(exc).__name__,
                        "error": str(exc),
                    }
                )
                continue
            for reaction in payload.get("records", []):
                if not isinstance(reaction, dict):
                    continue
                candidate_record_count += 1
                rows.append(
                    {
                        "accession": accession,
                        "countable_label_candidate": False,
                        "ec_number": ec_number,
                        "ec_specificity": ec_specificity,
                        "entry_id": item.get("entry_id"),
                        "equation": reaction.get("equation"),
                        "evidence_status": "reaction_context_only",
                        "lane_id": context.get("lane_id"),
                        "mapped_enzyme_count": reaction.get("mapped_enzyme_count"),
                        "ready_for_label_import": False,
                        "rhea_id": reaction.get("rhea_id"),
                        "scope_signal": context.get("scope_signal"),
                    }
                )
        candidate_summaries.append(
            {
                "accession": accession,
                "broad_or_incomplete_ec_numbers": sorted(candidate_broad_ec_numbers),
                "ec_numbers": ec_numbers,
                "reaction_record_count": candidate_record_count,
            }
        )
    return {
        "metadata": {
            "method": "external_source_reaction_evidence_sample",
            "ready_for_label_import": False,
            "countable_label_candidate_count": 0,
            "max_candidates": max_candidates,
            "max_reactions_per_ec": max_reactions_per_ec,
            "candidate_count": len(review_items),
            "candidate_with_reaction_context_count": sum(
                1
                for summary in candidate_summaries
                if summary["reaction_record_count"] > 0
            ),
            "queried_ec_count": len(queried_ec_numbers),
            "broad_or_incomplete_ec_count": len(broad_ec_numbers),
            "broad_or_incomplete_ec_numbers": sorted(broad_ec_numbers),
            "reaction_record_count": len(rows),
            "fetch_failure_count": len(fetch_failures),
            "review_only_rule": (
                "Rhea reaction context is evidence to review; it is not active-site "
                "mapping and cannot create countable labels"
            ),
        },
        "candidate_summaries": candidate_summaries,
        "rows": rows,
        "fetch_failures": fetch_failures,
        "blockers": [
            "reaction_context_not_mapped_to_candidate_active_site",
            "heuristic_control_scores_not_computed",
            "external_decision_artifact_not_built",
            "not_label_factory_gated",
        ],
    }


def audit_external_source_reaction_evidence_sample(
    reaction_evidence_sample: dict[str, Any],
) -> dict[str, Any]:
    """Verify reaction-context rows remain review evidence, not labels."""
    rows = [
        row
        for row in reaction_evidence_sample.get("rows", [])
        if isinstance(row, dict)
    ]
    countable_rows = [
        row for row in rows if row.get("countable_label_candidate") is not False
    ]
    import_ready_rows = [
        row for row in rows if row.get("ready_for_label_import") is not False
    ]
    non_context_rows = [
        row for row in rows if row.get("evidence_status") != "reaction_context_only"
    ]
    broad_ec_rows = [
        row for row in rows if row.get("ec_specificity") == "broad_or_incomplete"
    ]
    blockers: list[str] = []
    if countable_rows:
        blockers.append("reaction_context_rows_marked_countable")
    if import_ready_rows:
        blockers.append("reaction_context_rows_marked_ready_for_import")
    if non_context_rows:
        blockers.append("reaction_context_rows_missing_review_only_status")
    if not rows:
        blockers.append("empty_reaction_evidence_sample")
    return {
        "metadata": {
            "method": "external_source_reaction_evidence_guardrail_audit",
            "ready_for_label_import": False,
            "countable_label_candidate_count": len(countable_rows),
            "reaction_record_count": len(rows),
            "import_ready_row_count": len(import_ready_rows),
            "non_context_row_count": len(non_context_rows),
            "broad_ec_context_row_count": len(broad_ec_rows),
            "broad_or_incomplete_ec_numbers": sorted(
                {str(row.get("ec_number")) for row in broad_ec_rows}
            ),
            "fetch_failure_count": reaction_evidence_sample.get("metadata", {}).get(
                "fetch_failure_count", 0
            ),
            "guardrail_clean": not blockers,
        },
        "blockers": blockers,
        "warnings": [
            (
                "reaction context requires active-site mapping and factory gates "
                "before any external label import"
            )
        ],
    }


def _external_active_site_evidence_status(
    *,
    active_features: list[dict[str, Any]],
    binding_features: list[dict[str, Any]],
    catalytic_comments: list[dict[str, Any]],
) -> str:
    if active_features and catalytic_comments:
        return "active_site_and_catalytic_activity_context_found"
    if active_features:
        return "active_site_feature_context_found"
    if binding_features or catalytic_comments:
        return "binding_or_reaction_context_only"
    return "active_site_feature_missing"


def _external_active_site_evidence_blockers(
    *,
    queue_row: dict[str, Any],
    active_features: list[dict[str, Any]],
    catalytic_comments: list[dict[str, Any]],
) -> list[str]:
    blockers = [
        "active_site_features_not_mapped_to_candidate_structure",
        "heuristic_control_scores_not_computed",
        "external_decision_artifact_not_built",
        "not_label_factory_gated",
    ]
    if not active_features:
        blockers.append("uniprot_active_site_feature_missing")
    if not catalytic_comments:
        blockers.append("uniprot_catalytic_activity_comment_missing")
    if queue_row.get("broad_or_incomplete_ec_numbers"):
        blockers.append("specific_reaction_disambiguation_for_broad_ec")
    return blockers


def _external_active_site_feature_row(
    *,
    accession: str,
    queue_row: dict[str, Any],
    feature: dict[str, Any],
) -> dict[str, Any]:
    return {
        "accession": accession,
        "begin": feature.get("begin"),
        "countable_label_candidate": False,
        "description": feature.get("description"),
        "end": feature.get("end"),
        "evidence": feature.get("evidence", []),
        "evidence_status": "uniprot_feature_context_only",
        "feature_type": feature.get("feature_type"),
        "lane_id": queue_row.get("lane_id"),
        "ligand_id": feature.get("ligand_id"),
        "ligand_name": feature.get("ligand_name"),
        "ligand_note": feature.get("ligand_note"),
        "queue_rank": queue_row.get("rank"),
        "ready_for_label_import": False,
        "scope_signal": queue_row.get("scope_signal"),
    }


def _external_heuristic_control_blockers(queue_status: str) -> list[str]:
    blockers = [
        "heuristic_control_scores_not_computed",
        "external_decision_artifact_not_built",
        "full_label_factory_gate_not_run",
    ]
    if queue_status == "defer_active_site_feature_gap":
        blockers.append("uniprot_active_site_feature_missing")
    elif queue_status == "defer_catalytic_activity_gap":
        blockers.append("uniprot_catalytic_activity_comment_missing")
    elif queue_status == "defer_broad_ec_disambiguation":
        blockers.append("specific_reaction_disambiguation_for_broad_ec")
    return blockers


def _external_structure_mapping_blockers(mapping_status: str) -> list[str]:
    blockers = [
        "structure_mapping_not_computed",
        "heuristic_control_scores_not_computed",
        "external_decision_artifact_not_built",
        "full_label_factory_gate_not_run",
    ]
    if mapping_status == "defer_before_structure_mapping":
        blockers.append("upstream_evidence_or_disambiguation_deferred")
    elif mapping_status == "defer_active_site_positions_missing":
        blockers.append("uniprot_active_site_feature_missing")
    elif mapping_status == "defer_structure_reference_missing":
        blockers.append("external_structure_reference_missing")
    return blockers


def fetch_external_structure_cif(structure_source: str, structure_id: str) -> str:
    if structure_source == "alphafold":
        errors: list[str] = []
        for version in ALPHAFOLD_MODEL_VERSIONS:
            request = Request(
                ALPHAFOLD_CIF_URL.format(accession=structure_id, version=version),
                headers={"User-Agent": USER_AGENT},
            )
            try:
                with urlopen(request, timeout=30) as response:
                    return response.read().decode("utf-8", errors="replace")
            except Exception as exc:  # pragma: no cover - live-source fallback
                errors.append(f"v{version}:{type(exc).__name__}")
                continue
        raise ValueError(
            f"AlphaFold CIF fetch failed for {structure_id} across versions "
            f"{', '.join(errors)}"
        )
    if structure_source == "pdb":
        return fetch_pdb_cif(structure_id)
    raise ValueError(f"unsupported structure source: {structure_source}")


def _external_structural_index_choice(
    row: dict[str, Any],
) -> tuple[str | None, str | None]:
    alphafold_ids = [
        _normalize_alphafold_model_accession(item)
        for item in row.get("alphafold_ids", []) or row.get("alphafold_ids_sample", [])
        if _normalize_alphafold_model_accession(item)
    ]
    if alphafold_ids:
        return "alphafold", alphafold_ids[0]
    pdb_ids = [
        str(item).strip().upper()
        for item in (
            row.get("pdb_reference_examples", []) or row.get("pdb_ids_sample", [])
        )
        if str(item).strip()
    ]
    if pdb_ids:
        return "pdb", pdb_ids[0]
    return None, None


def _external_coordinate_file_name(structure_source: str, structure_id: str) -> str:
    source_prefix = "afdb" if structure_source == "alphafold" else "pdb"
    safe_id = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(structure_id).strip())
    return f"{source_prefix}_{safe_id}.cif"


def _external_foldseek_binary_info(foldseek_binary: str) -> dict[str, Any]:
    requested = str(foldseek_binary)
    requested_path = Path(requested)
    resolved = (
        str(requested_path)
        if requested_path.exists()
        else shutil.which(requested)
    )
    info: dict[str, Any] = {
        "requested": requested,
        "resolved": resolved,
        "available": bool(resolved),
        "version": None,
    }
    if not resolved:
        return info
    try:
        result = subprocess.run(
            [resolved, "version"],
            check=True,
            capture_output=True,
            text=True,
            timeout=20,
        )
        info["version"] = (result.stdout or result.stderr).strip().splitlines()[0]
    except Exception as exc:  # pragma: no cover - backend-specific fallback
        info["version"] = f"version_unavailable:{type(exc).__name__}"
    return info


def _external_run_backend_command(command: list[str], *, cwd: Path) -> None:
    result = subprocess.run(command, cwd=cwd, capture_output=True, text=True)
    if result.returncode != 0:
        stderr = (result.stderr or result.stdout or "").strip()
        raise RuntimeError(stderr or f"backend command failed: {command[0]}")


def _external_coordinate_aliases(
    materialized_rows: list[dict[str, Any]],
) -> dict[str, str]:
    aliases: dict[str, str] = {}
    for row in materialized_rows:
        accession = str(row["accession"])
        structure_id = str(row.get("structure_id") or accession)
        path = Path(str(row["coordinate_path"]))
        raw_aliases = {
            accession,
            structure_id,
            path.name,
            path.stem,
            str(path),
            f"afdb_{structure_id}",
            f"pdb_{structure_id}",
            f"AF-{structure_id}-F1-model_v6",
        }
        for alias in raw_aliases:
            if alias:
                aliases[str(alias)] = accession
    return aliases


def _current_countable_foldseek_coordinate_groups(
    foldseek_coordinate_readiness: dict[str, Any],
) -> list[dict[str, Any]]:
    groups_by_path: dict[str, dict[str, Any]] = {}
    materialized_statuses = {
        "already_materialized",
        "coordinate_sidecar_materialized",
        "coordinate_sidecar_reused",
        "materialized",
    }
    for row in foldseek_coordinate_readiness.get("rows", []) or []:
        if not isinstance(row, dict):
            continue
        coordinate_path = row.get("coordinate_path")
        if not coordinate_path:
            continue
        status = str(row.get("coordinate_materialization_status") or "")
        if status and status not in materialized_statuses:
            continue
        path = Path(str(coordinate_path))
        if not path.exists():
            continue
        key = str(path)
        group = groups_by_path.setdefault(
            key,
            {
                "coordinate_key": key,
                "coordinate_path": key,
                "selected_structure_key": row.get("selected_structure_key"),
                "selected_structure_id": row.get("selected_structure_id"),
                "selected_structure_source": row.get("selected_structure_source"),
                "entry_ids": [],
                "label_types": [],
                "target_fingerprint_ids": [],
                "rows": [],
            },
        )
        entry_id = row.get("entry_id")
        if entry_id and entry_id not in group["entry_ids"]:
            group["entry_ids"].append(entry_id)
        label_type = row.get("label_type")
        if label_type and label_type not in group["label_types"]:
            group["label_types"].append(label_type)
        fingerprint_id = row.get("target_fingerprint_id")
        if fingerprint_id and fingerprint_id not in group["target_fingerprint_ids"]:
            group["target_fingerprint_ids"].append(fingerprint_id)
        group["rows"].append(row)
    groups = list(groups_by_path.values())
    for group in groups:
        group["entry_ids"] = sorted(str(item) for item in group["entry_ids"])
        group["label_types"] = sorted(str(item) for item in group["label_types"])
        group["target_fingerprint_ids"] = sorted(
            str(item) for item in group["target_fingerprint_ids"]
        )
    return sorted(
        groups,
        key=lambda group: (
            str(group.get("selected_structure_key") or ""),
            str(group.get("coordinate_path") or ""),
        ),
    )


def _current_countable_foldseek_aliases(
    current_groups: list[dict[str, Any]],
) -> dict[str, str]:
    aliases: dict[str, str] = {}
    for group in current_groups:
        coordinate_key = str(group["coordinate_key"])
        path = Path(str(group["coordinate_path"]))
        structure_id = str(group.get("selected_structure_id") or "")
        structure_key = str(group.get("selected_structure_key") or "")
        source = str(group.get("selected_structure_source") or "")
        raw_aliases = {
            coordinate_key,
            str(path),
            path.name,
            path.stem,
            structure_id,
            structure_key,
            f"{source}_{structure_id}" if source and structure_id else "",
        }
        for alias in raw_aliases:
            if alias:
                aliases[str(alias)] = coordinate_key
    return aliases


def _external_foldseek_name_candidates(raw_name: str) -> list[str]:
    text = str(raw_name or "").strip()
    if not text:
        return []
    path = Path(text)
    candidates = [text, path.name, path.stem]
    if "." in path.name:
        candidates.append(path.name.rsplit(".", 1)[0])
    if "_" in path.stem:
        parts = path.stem.split("_")
        if len(parts) > 1:
            candidates.append("_".join(parts[:-1]))
    return list(dict.fromkeys(candidate for candidate in candidates if candidate))


def _parse_external_foldseek_pairs(
    *,
    result_tsv: Path,
    alias_to_accession: dict[str, str],
) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not result_tsv.exists():
        raise ValueError(f"Foldseek result TSV does not exist: {result_tsv}")
    for line in result_tsv.read_text(encoding="utf-8").splitlines():
        if not line.strip():
            continue
        parts = line.split("\t")
        if len(parts) < 5:
            continue
        raw_query, raw_target = parts[0], parts[1]
        query_accession = _external_map_foldseek_name(raw_query, alias_to_accession)
        target_accession = _external_map_foldseek_name(raw_target, alias_to_accession)
        qtmscore = _external_parse_float(parts[2])
        ttmscore = _external_parse_float(parts[3])
        alntmscore = _external_parse_float(parts[4])
        score_values = [
            score
            for score in (qtmscore, ttmscore, alntmscore)
            if score is not None
        ]
        rows.append(
            {
                "raw_query_name": raw_query,
                "raw_target_name": raw_target,
                "query_accession": query_accession,
                "target_accession": target_accession,
                "qtmscore": qtmscore,
                "ttmscore": ttmscore,
                "alntmscore": alntmscore,
                "max_pair_tm_score": max(score_values) if score_values else None,
                "mapped": bool(query_accession and target_accession),
            }
        )
    return rows


def _parse_external_vs_current_foldseek_pairs(
    *,
    result_tsv: Path,
    query_aliases: dict[str, str],
    target_aliases: dict[str, str],
) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not result_tsv.exists():
        raise ValueError(f"Foldseek result TSV does not exist: {result_tsv}")
    for line in result_tsv.read_text(encoding="utf-8").splitlines():
        if not line.strip():
            continue
        parts = line.split("\t")
        if len(parts) < 5:
            continue
        raw_query, raw_target = parts[0], parts[1]
        query_accession = _external_map_foldseek_name(raw_query, query_aliases)
        target_coordinate_key = _external_map_foldseek_name(raw_target, target_aliases)
        qtmscore = _external_parse_float(parts[2])
        ttmscore = _external_parse_float(parts[3])
        alntmscore = _external_parse_float(parts[4])
        score_values = [
            score
            for score in (qtmscore, ttmscore)
            if score is not None
        ]
        rows.append(
            {
                "raw_query_name": raw_query,
                "raw_target_name": raw_target,
                "query_accession": query_accession,
                "target_coordinate_key": target_coordinate_key,
                "qtmscore": qtmscore,
                "ttmscore": ttmscore,
                "alntmscore": alntmscore,
                "max_pair_tm_score": max(score_values) if score_values else None,
                "mapped": bool(query_accession and target_coordinate_key),
            }
        )
    return rows


def _external_map_foldseek_name(
    raw_name: str,
    alias_to_accession: dict[str, str],
) -> str | None:
    for candidate in _external_foldseek_name_candidates(raw_name):
        if candidate in alias_to_accession:
            return alias_to_accession[candidate]
    return None


def _external_parse_float(value: Any) -> float | None:
    try:
        if value is None or str(value).strip() == "":
            return None
        return float(value)
    except (TypeError, ValueError):
        return None


def _external_parse_int(value: Any) -> int:
    parsed = _external_parse_float(value)
    return int(parsed) if parsed is not None else 0


def _external_unordered_tm_pairs(
    pair_rows: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    pairs: dict[tuple[str, str], dict[str, Any]] = {}
    for row in pair_rows:
        query = row.get("query_accession")
        target = row.get("target_accession")
        if not query or not target or query == target:
            continue
        score = _external_parse_float(row.get("max_pair_tm_score"))
        if score is None:
            continue
        left, right = sorted((str(query), str(target)))
        key = (left, right)
        current = pairs.get(key)
        if current is None or score > float(current.get("max_pair_tm_score") or 0.0):
            pairs[key] = {
                "left_accession": left,
                "right_accession": right,
                "max_pair_tm_score": round(score, 4),
                "qtmscore": row.get("qtmscore"),
                "ttmscore": row.get("ttmscore"),
                "alntmscore": row.get("alntmscore"),
                "raw_query_name": row.get("raw_query_name"),
                "raw_target_name": row.get("raw_target_name"),
            }
    return list(pairs.values())


def _external_nearest_tm_neighbors(
    unordered_pairs: list[dict[str, Any]],
) -> dict[str, dict[str, Any]]:
    nearest: dict[str, dict[str, Any]] = {}
    for pair in unordered_pairs:
        left = str(pair["left_accession"])
        right = str(pair["right_accession"])
        score = float(pair.get("max_pair_tm_score") or 0.0)
        for accession, neighbor in ((left, right), (right, left)):
            current = nearest.get(accession)
            if current is None or score > float(current.get("tm_score") or 0.0):
                nearest[accession] = {
                    "accession": neighbor,
                    "tm_score": round(score, 4),
                }
    return nearest


def _external_tm_clusters(
    accessions: list[str],
    unordered_pairs: list[dict[str, Any]],
    *,
    threshold: float,
) -> list[dict[str, Any]]:
    parent = {accession: accession for accession in accessions}

    def find(accession: str) -> str:
        while parent[accession] != accession:
            parent[accession] = parent[parent[accession]]
            accession = parent[accession]
        return accession

    def union(left: str, right: str) -> None:
        left_root = find(left)
        right_root = find(right)
        if left_root != right_root:
            parent[max(left_root, right_root)] = min(left_root, right_root)

    for pair in unordered_pairs:
        if float(pair.get("max_pair_tm_score") or 0.0) >= threshold:
            union(str(pair["left_accession"]), str(pair["right_accession"]))

    members_by_root: dict[str, list[str]] = {}
    for accession in accessions:
        members_by_root.setdefault(find(accession), []).append(accession)

    clusters = []
    for index, (_, members) in enumerate(
        sorted(members_by_root.items(), key=lambda item: (item[1][0], item[0])),
        start=1,
    ):
        sorted_members = sorted(members)
        clusters.append(
            {
                "cluster_id": f"external_tm_cluster:{index:03d}",
                "accessions": sorted_members,
                "member_count": len(sorted_members),
                "threshold_rule": f"connected_components_at_tm_score_ge_{threshold:.1f}",
            }
        )
    return clusters


def _safe_ratio(numerator: int, denominator: int) -> float | None:
    if denominator <= 0:
        return None
    return round(float(numerator) / float(denominator), 4)


def _external_structure_choice(row: dict[str, Any]) -> tuple[str | None, str | None]:
    alphafold_ids = [
        _normalize_alphafold_model_accession(item)
        for item in row.get("alphafold_ids_sample", [])
        if _normalize_alphafold_model_accession(item)
    ]
    if alphafold_ids:
        return "alphafold", alphafold_ids[0]
    pdb_ids = [
        str(item).strip().upper()
        for item in row.get("pdb_ids_sample", [])
        if str(item).strip()
    ]
    if pdb_ids:
        return "pdb", pdb_ids[0]
    return None, None


def _normalize_alphafold_model_accession(value: Any) -> str:
    text = str(value or "").strip()
    if text.startswith("AF-") and "-F1" in text:
        return text.removeprefix("AF-").split("-F1", 1)[0]
    return text


